export interface Question {
  q: string;
  options: string[];
  answer: number; // index of correct option
  explanation: string;
  difficulty: 'easy' | 'medium' | 'hard';
}

// ─── FOUNDATION QA (60 questions) ─────────────────────────────────────────────
export const FOUNDATION: Question[] = [
  { q: "What does SDLC stand for?", options: ["Software Development Life Cycle", "System Design and Launch Cycle", "Software Defect Lifecycle Check", "System Delivery Lifecycle"], answer: 0, explanation: "SDLC = Software Development Life Cycle — the structured process for planning, creating, testing, and delivering software.", difficulty: 'easy' },
  { q: "Which phase of STLC involves writing actual test scripts?", options: ["Test Planning", "Test Analysis", "Test Implementation", "Test Execution"], answer: 2, explanation: "Test Implementation (or Test Design) is when testers write and prepare test scripts/cases based on the test plan and analysis.", difficulty: 'easy' },
  { q: "What is the primary purpose of a test plan?", options: ["List all bugs found", "Define scope, approach, resources and schedule for testing", "Write test cases", "Execute regression tests"], answer: 1, explanation: "A test plan outlines the scope, objectives, approach, resources, schedule, and deliverables for a testing effort.", difficulty: 'easy' },
  { q: "In the defect lifecycle, after a defect is 'Fixed', what is the typical next state?", options: ["Closed", "Reopen", "Ready for Retest", "Deferred"], answer: 2, explanation: "After a developer marks a defect as Fixed, it moves to 'Ready for Retest' so QA can verify the fix worked.", difficulty: 'easy' },
  { q: "Equivalence partitioning divides input data into:", options: ["Random groups", "Valid and invalid partitions where all values behave identically", "Equal-sized numeric ranges", "Groups based on code coverage"], answer: 1, explanation: "EP divides inputs into classes where any value within the class should produce the same result — you only need to test one value per class.", difficulty: 'easy' },
  { q: "Boundary Value Analysis tests values at:", options: ["The center of each partition", "The boundaries and just inside/outside partition edges", "Random points in the data range", "Any equivalent value in a partition"], answer: 1, explanation: "BVA tests at the exact boundary, one below, and one above — defects often hide at boundaries where conditions switch.", difficulty: 'easy' },
  { q: "Which test level verifies individual components in isolation?", options: ["System Testing", "Acceptance Testing", "Unit Testing", "Integration Testing"], answer: 2, explanation: "Unit testing verifies individual functions, methods, or classes in isolation — typically done by developers.", difficulty: 'easy' },
  { q: "What is the key difference between Verification and Validation?", options: ["Verification is done by QA; Validation by developers", "Verification checks we built the product right; Validation checks we built the right product", "Verification is automated; Validation is manual", "They mean the same thing"], answer: 1, explanation: "Verification = 'Are we building the product right?' (process-oriented). Validation = 'Are we building the right product?' (outcome-oriented).", difficulty: 'medium' },
  { q: "What is the 'Pesticide Paradox'?", options: ["Bugs multiply faster than testers can find them", "Repeatedly running the same tests will find fewer new defects over time", "Tests become toxic and unreliable", "Using too many test tools slows you down"], answer: 1, explanation: "The Pesticide Paradox: like pesticides that lose effectiveness, repeated test execution finds fewer new bugs. Tests must evolve.", difficulty: 'medium' },
  { q: "What does 'shift-left testing' mean?", options: ["Running tests from right to left", "Moving testing activities earlier in the SDLC to catch defects sooner", "Testing only the left side of the UI", "Prioritising lower-priority tests"], answer: 1, explanation: "Shift-left moves testing earlier (to the 'left' of the timeline) — catching bugs in requirements and design phases is far cheaper.", difficulty: 'easy' },
  { q: "Which metric measures the percentage of code executed by tests?", options: ["Requirements coverage", "Defect density", "Code coverage", "Test pass rate"], answer: 2, explanation: "Code coverage (e.g., statement, branch coverage) measures what % of code was executed by the test suite.", difficulty: 'easy' },
  { q: "A 'smoke test' is best described as:", options: ["A deep test of a specific feature area", "A broad, shallow check to confirm a build is stable enough to test", "A test for performance under heavy load", "A security penetration test"], answer: 1, explanation: "Smoke tests are quick, broad checks ('does the engine start?') run after each build to gate further testing.", difficulty: 'easy' },
  { q: "What is User Acceptance Testing (UAT)?", options: ["Testing done by the development team", "Final validation by real users/stakeholders before go-live", "Automated regression testing", "Unit testing of user interface components"], answer: 1, explanation: "UAT is performed by business stakeholders or end-users to confirm the software meets real-world requirements before release.", difficulty: 'easy' },
  { q: "Which test design technique uses a table of inputs and expected outputs to cover all combinations?", options: ["Boundary Value Analysis", "Decision Table Testing", "State Transition Testing", "Equivalence Partitioning"], answer: 1, explanation: "Decision tables list all combinations of conditions and their corresponding actions — great for complex business rules.", difficulty: 'medium' },
  { q: "What is a 'test oracle'?", options: ["A QA management tool", "A mechanism to determine whether a test passed or failed", "A test automation framework", "A performance benchmarking service"], answer: 1, explanation: "A test oracle provides the expected output to compare against actual output — it can be a human, a specification, or another system.", difficulty: 'medium' },
  { q: "What does 'exploratory testing' involve?", options: ["Following a detailed pre-written test script exactly", "Simultaneously learning, designing and executing tests using domain knowledge", "Automating existing test cases", "Measuring system performance"], answer: 1, explanation: "Exploratory testing is unscripted — testers use their knowledge to explore the system, design tests, and execute them on the fly.", difficulty: 'easy' },
  { q: "Regression testing is primarily used to:", options: ["Test brand-new features for the first time", "Verify existing functionality still works after code changes", "Check system performance under load", "Validate user interface design"], answer: 1, explanation: "Regression testing re-runs existing tests after any change to ensure previously working functionality wasn't broken.", difficulty: 'easy' },
  { q: "Which severity level typically blocks a release?", options: ["Low", "Medium", "High", "Critical / Blocker"], answer: 3, explanation: "Critical/Blocker defects prevent core functionality from working (e.g., login broken) and must be fixed before release.", difficulty: 'easy' },
  { q: "What is the purpose of a 'test stub' in integration testing?", options: ["A complete replacement module for integration", "A simplified simulation of a called component used in top-down testing", "A mock of the user interface", "A record of test execution results"], answer: 1, explanation: "A stub simulates the behaviour of a lower-level component that hasn't been built yet — used in top-down integration testing.", difficulty: 'medium' },
  { q: "In Agile, who is primarily responsible for quality?", options: ["Only the QA team", "Only the product owner", "The entire cross-functional team", "Only developers"], answer: 2, explanation: "In Agile, quality is a shared team responsibility — developers, QA, and POs all contribute to built-in quality.", difficulty: 'easy' },
  { q: "What does 'Definition of Done' mean in Agile?", options: ["A list of known bugs to fix later", "A shared checklist of quality criteria a story must meet before it's complete", "The acceptance criteria for a single feature", "A sprint planning document"], answer: 1, explanation: "DoD is the team's agreed-upon quality bar for 'done' — includes code review, tests written, CI passing, documentation updated, etc.", difficulty: 'easy' },
  { q: "Which document maps test cases back to requirements?", options: ["Test execution report", "Defect log", "Requirements Traceability Matrix (RTM)", "Test plan"], answer: 2, explanation: "An RTM maps each requirement to its test cases, ensuring full requirements coverage and impact analysis when requirements change.", difficulty: 'medium' },
  { q: "What is 'risk-based testing'?", options: ["Testing without any plan", "Prioritising test efforts based on probability and impact of failures", "Running all tests regardless of time constraints", "Testing only the highest-risk code modules"], answer: 1, explanation: "Risk-based testing allocates test effort proportional to the risk (likelihood × impact) of each area failing in production.", difficulty: 'medium' },
  { q: "A 'sanity test' differs from a smoke test in that it is:", options: ["Broader and covers the whole application", "Narrower and verifies a specific fix or change area", "Automated rather than manual", "Done before a new build is deployed"], answer: 1, explanation: "Sanity testing is narrow and deep — used to quickly verify a specific fix worked correctly, after smoke testing confirms the build is stable.", difficulty: 'medium' },
  { q: "What is 'static testing'?", options: ["Testing without any movement in the UI", "Reviewing code, requirements or design without executing the software", "Testing on static web pages only", "Performance testing under constant load"], answer: 1, explanation: "Static testing involves reviewing artefacts (code, specs, designs) without running the software — includes walkthroughs, inspections, and static analysis.", difficulty: 'medium' },
  { q: "What does 'test coverage' primarily measure?", options: ["Number of test cases executed", "Proportion of a defined test basis exercised by the test suite", "Time taken to run tests", "Number of defects found"], answer: 1, explanation: "Test coverage measures how much of the defined scope (requirements, code branches, conditions) has been tested.", difficulty: 'medium' },
  { q: "Which testing type focuses on verifying that a system can withstand expected and peak loads?", options: ["Smoke testing", "Regression testing", "Performance/Load testing", "Usability testing"], answer: 2, explanation: "Load/performance testing verifies system behaviour under expected load and helps find performance bottlenecks before production.", difficulty: 'easy' },
  { q: "What is the main benefit of test automation?", options: ["Eliminates the need for manual testing entirely", "Enables fast, repeatable execution of regression tests at scale", "Automatically finds all bugs", "Removes the need for a test plan"], answer: 1, explanation: "Automation shines for regression — running hundreds of tests in minutes on every code change, freeing humans for exploratory and edge-case testing.", difficulty: 'easy' },
  { q: "What is 'negative testing'?", options: ["Testing features that are expected to fail", "Testing with invalid, unexpected, or boundary-exceeding input", "Criticising the software in testing", "Testing only error handling code"], answer: 1, explanation: "Negative testing validates how the system handles invalid, unexpected or out-of-range inputs — ensuring it fails gracefully.", difficulty: 'easy' },
  { q: "In state transition testing, what does a 'state' represent?", options: ["A test step", "A condition or status of the system at a point in time", "A defect status", "A test environment"], answer: 1, explanation: "A state is a stable condition of the system (e.g., 'Logged In', 'Cart Empty') that persists until an event triggers a transition.", difficulty: 'medium' },
  { q: "What is a 'test harness'?", options: ["A document template for test cases", "A collection of software and test data configured to test a program unit", "A physical test lab setup", "A bug tracking tool"], answer: 1, explanation: "A test harness is the infrastructure (drivers, stubs, test data, configuration) needed to run tests on a component under test.", difficulty: 'hard' },
  { q: "Which type of testing checks the software against its specification without knowing the internal code?", options: ["White-box testing", "Grey-box testing", "Black-box testing", "Clear-box testing"], answer: 2, explanation: "Black-box testing treats the system as a black box — you only know inputs and expected outputs, not the internal implementation.", difficulty: 'easy' },
  { q: "What does ISTQB stand for?", options: ["International Software Testing Qualification Board", "Institute of Software Test Quality Benchmarks", "International Standard Testing and Quality Bureau", "Integrated Software Testing and QA Board"], answer: 0, explanation: "ISTQB = International Software Testing Qualifications Board — the global body issuing QA certifications like Foundation and Advanced.", difficulty: 'easy' },
  { q: "Which of the following is a characteristic of good test cases?", options: ["Vague expected results", "Independence from other test cases where possible", "As long as possible for completeness", "Written after execution"], answer: 1, explanation: "Good test cases are independent, have clear expected results, cover one thing at a time, and can be executed by anyone who reads them.", difficulty: 'medium' },
  { q: "What is 'alpha testing'?", options: ["Testing done by external users in their environment", "Internal testing done by the development team or QA before release", "The first ever test run on the system", "Automated regression testing"], answer: 1, explanation: "Alpha testing is internal acceptance testing — done by the vendor's own team or internal users before releasing to external users.", difficulty: 'medium' },
  { q: "What is 'beta testing'?", options: ["Testing done by developers before code review", "External testing done by selected real users before general release", "The second phase of automated testing", "Load testing in a staging environment"], answer: 1, explanation: "Beta testing is done by real external users in their environment — it catches real-world usability and environment-specific issues.", difficulty: 'easy' },
  { q: "What does 'defect density' measure?", options: ["How quickly bugs are fixed", "Number of confirmed defects per unit of code size (e.g., per KLOC)", "The total number of defects in the backlog", "The ratio of critical to minor defects"], answer: 1, explanation: "Defect density = defects / size (e.g., per 1000 lines of code or per function point) — used to compare module quality.", difficulty: 'medium' },
  { q: "Which of these is an example of a non-functional requirement?", options: ["The login form must accept email and password", "The page must load in under 2 seconds for 95% of users", "Users can reset their password via email", "The shopping cart must support up to 50 items"], answer: 1, explanation: "Non-functional requirements define quality attributes (performance, security, usability, reliability) — how the system behaves, not what it does.", difficulty: 'medium' },
  { q: "What is the correct order of STLC phases?", options: ["Execute → Plan → Design → Closure", "Plan → Analyse → Design → Implement → Execute → Closure", "Design → Plan → Execute → Analyse", "Execute → Analyse → Plan → Design → Closure"], answer: 1, explanation: "STLC: Test Planning → Test Analysis → Test Design → Test Implementation → Test Execution → Test Cycle Closure.", difficulty: 'medium' },
  { q: "What is a 'test condition'?", options: ["The hardware environment for testing", "An item or event that can be verified by tests, derived from a test basis", "A mandatory precondition for running a test", "A type of test assertion"], answer: 1, explanation: "A test condition is a testable aspect of the software (a feature, rule, or behaviour) derived from requirements — it's what you want to test.", difficulty: 'hard' },
  { q: "What does 'test basis' refer to?", options: ["The base URL of the test environment", "All documentation and knowledge used to create test cases", "The baseline test execution metrics", "The foundational test automation framework"], answer: 1, explanation: "The test basis is all the artefacts used to identify test conditions — requirements docs, design specs, user stories, acceptance criteria.", difficulty: 'hard' },
  { q: "Which technique is best for testing a login form with valid/invalid combinations?", options: ["State transition testing", "Decision table testing", "Use case testing", "Statement coverage"], answer: 1, explanation: "Decision table testing is ideal for logic with multiple input combinations (e.g., valid/invalid username × valid/invalid password = 4 combinations).", difficulty: 'medium' },
  { q: "What is 'end-to-end testing'?", options: ["Testing the last module in the system", "Testing complete user workflows from start to finish across all system layers", "Testing only the API endpoints", "Testing the system under maximum load"], answer: 1, explanation: "E2E testing validates entire user journeys (e.g., register → browse → checkout → order confirmation) across frontend, backend, and database.", difficulty: 'easy' },
  { q: "What is the purpose of a 'test exit criteria'?", options: ["Define when a tester has been hired", "Define conditions that must be met to consider testing complete", "Set the pass mark for certification exams", "List the tests that will be skipped"], answer: 1, explanation: "Exit criteria define when testing can stop — e.g., 95% of planned test cases executed, no open Critical defects, 90% pass rate.", difficulty: 'medium' },
  { q: "What is 'usability testing'?", options: ["Testing system speed and throughput", "Evaluating how easy and intuitive the product is for real users", "Testing the API documentation", "Checking all button labels are correct"], answer: 1, explanation: "Usability testing observes real users interacting with the product to identify pain points, confusion, and design issues.", difficulty: 'easy' },
  { q: "Which level of testing is closest to the end-user perspective?", options: ["Unit testing", "Integration testing", "System testing", "Acceptance testing"], answer: 3, explanation: "Acceptance testing is closest to the end-user — it validates the complete system meets business requirements from a user perspective.", difficulty: 'easy' },
  { q: "What is 'cross-browser testing'?", options: ["Testing that works the same in Chrome and Firefox only", "Verifying application behaviour is consistent across different browsers and versions", "Testing browser extensions", "Comparing two browsers' speed"], answer: 1, explanation: "Cross-browser testing ensures consistent functionality and appearance across Chrome, Firefox, Safari, Edge, and their various versions.", difficulty: 'easy' },
  { q: "In test management, what is a 'test suite'?", options: ["A single test case with multiple steps", "A collection of test cases grouped together for execution", "A test execution environment", "A set of test automation tools"], answer: 1, explanation: "A test suite groups related test cases for organized execution — e.g., 'Login Test Suite' containing all login-related test cases.", difficulty: 'easy' },
  { q: "What is 'mutation testing'?", options: ["Testing AI model outputs", "Introducing small code changes to verify that tests detect them", "Testing with extreme input values", "Changing test cases to improve coverage"], answer: 1, explanation: "Mutation testing injects small faults ('mutations') into code to check if existing tests catch them — measures test suite effectiveness.", difficulty: 'hard' },
  { q: "What does 'flaky test' mean?", options: ["A test written in Python", "A test that intermittently passes and fails without code changes", "A test with poor coverage", "A test that always fails"], answer: 1, explanation: "Flaky tests are non-deterministic — they sometimes pass, sometimes fail without any code change, usually due to timing, environment, or test order issues.", difficulty: 'medium' },
  { q: "What is 'test data management'?", options: ["Backing up test scripts", "Creating, maintaining, and securing data used in testing", "Managing test tool licences", "Archiving test reports"], answer: 1, explanation: "Test data management ensures the right data is available for tests — creation, masking of sensitive data, versioning, and cleanup.", difficulty: 'medium' },
  { q: "Which approach involves testing the software from the inside out, knowing the internal code structure?", options: ["Black-box testing", "Grey-box testing", "White-box testing", "Exploratory testing"], answer: 2, explanation: "White-box (clear-box) testing uses knowledge of the internal code to design tests targeting specific paths, branches, and conditions.", difficulty: 'easy' },
  { q: "What is the 'Seven Testing Principles' concept?", options: ["Seven steps to write test cases", "Fundamental guidelines for effective software testing practice", "Seven types of test automation frameworks", "Seven ISTQB certification levels"], answer: 1, explanation: "The 7 principles (e.g., 'Testing shows presence of defects, not absence'; 'Exhaustive testing is impossible') guide effective test strategy.", difficulty: 'medium' },
  { q: "What does 'test environment' include?", options: ["Only the server hardware", "Hardware, software, network, data, and configuration needed to run tests", "Only the test automation tools", "The test case documents"], answer: 1, explanation: "A test environment is the complete infrastructure — servers, databases, OS, browsers, test data, configs, and tools — needed to execute tests.", difficulty: 'easy' },
  { q: "What is 'performance testing' most concerned with?", options: ["Functional correctness of features", "System behaviour under load — speed, scalability, and stability", "Security vulnerabilities", "Cross-browser compatibility"], answer: 1, explanation: "Performance testing measures response time, throughput, resource usage, and stability under various load conditions.", difficulty: 'easy' },
  { q: "What does 'shift-right testing' involve?", options: ["Moving all tests to production", "Testing and monitoring in production to gather real-world usage data", "Delaying testing to the end of the SDLC", "Moving tests to the right column of a Kanban board"], answer: 1, explanation: "Shift-right extends testing into production using A/B testing, canary releases, feature flags, and production monitoring.", difficulty: 'hard' },
  { q: "What is the V-model in software testing?", options: ["A model where testing is done only after all development is complete", "A model showing the relationship between development phases and corresponding test levels", "A visual diagram of test case structure", "A model for visual/UI testing"], answer: 1, explanation: "The V-model pairs each development phase with a corresponding test level — requirements → acceptance test, design → system test, etc.", difficulty: 'medium' },
  { q: "What is 'accessibility testing'?", options: ["Testing if users can access the system over the internet", "Verifying the application is usable by people with disabilities", "Testing system login and authentication", "Checking file access permissions"], answer: 1, explanation: "Accessibility testing verifies compliance with standards like WCAG 2.1 — ensuring users with visual, hearing, motor, or cognitive disabilities can use the product.", difficulty: 'easy' },
  { q: "Which tool category is Jira?", options: ["Test automation framework", "Performance testing tool", "Defect/issue tracking tool", "Code coverage tool"], answer: 2, explanation: "Jira is an issue/project tracking tool commonly used to log, track, and manage defects and user stories in Agile teams.", difficulty: 'easy' },
  { q: "What does 'continuous testing' mean in CI/CD?", options: ["Running tests 24/7 manually", "Automated test execution triggered on every code commit in the pipeline", "Never stopping the test execution", "Testing every continuous deployment manually"], answer: 1, explanation: "Continuous testing integrates automated tests into the CI/CD pipeline so every commit triggers test execution, providing immediate quality feedback.", difficulty: 'medium' },
];

