// ─── HELPER ───────────────────────────────────────────────────────────────────

export type Domain = 'foundation' | 'automation' | 'ai-testing' | 'mixed';

export function getDomain(certName: string): Domain {
  const lower = certName.toLowerCase();
  if (lower.includes('autom') || lower.includes('playwright') || lower.includes('selenium') || lower.includes('cypress')) return 'automation';
  if (lower.includes('ai') || lower.includes('llm') || lower.includes('machine') || lower.includes('ct-ai')) return 'ai-testing';
  if (lower.includes('foundation') || lower.includes('istqb') || lower.includes('ctfl') || lower.includes('tester')) return 'foundation';
  return 'mixed';
}

export function pickExamQuestions(certName: string, count = 50): Question[] {
  const domain = getDomain(certName);
  let pool: Question[];
  if (domain === 'automation') {
    pool = [...FOUNDATION.slice(0, 20), ...AUTOMATION];
  } else if (domain === 'ai-testing') {
    pool = [...FOUNDATION.slice(0, 20), ...AI_TESTING];
  } else if (domain === 'foundation') {
    pool = FOUNDATION;
  } else {
    pool = [...FOUNDATION.slice(0, 20), ...AUTOMATION.slice(0, 15), ...AI_TESTING.slice(0, 15)];
  }
  return [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(count, pool.length));
}
